<template>
    <div>
        <div :class="['menu', menuSwitch ? 'menu-ani-open' : 'menu-ani-close']" v-if="deviceType === 'pc'">
            <!-- <img src="./../../assets/images/logo-white.png" alt="" class="logo" v-if="menuSwitch"/> -->
            <el-menu
                mode="vertical"
                :collapse="!menuSwitch"
                :default-active="defalutcActive"
                class="el-menu-vertical-demo"
                @open="handleOpen"
                @close="handleClose"
                background-color="#1F2D52"
                text-color="#bfcbd9"
                active-text-color="#FFF">
                <el-menu-item :index="`${index+1}-1`" v-for="(item, index) in menuList" :key="index" @click="toPath(item)">
                    <i class="el-icon-menu"></i>
                    <span slot="title">{{item.meta.title}}</span>
                </el-menu-item>
            </el-menu>
        </div>
        <div v-else>
            <!-- <div class="showMenu center" @click="showMenu">
                <van-icon name="arrow" />
            </div> -->
            <van-popup
                v-model="menuSwitch2"
                position="left"
                :style="style"
                @click-overlay="closeMenu">
                <div class="menuList">
                    <div :class="['item', ]"  @click="toPath(item)"
                        v-for="(item, index) in menuList" :key="index">
                        {{item.meta.title}}
                    </div>
                </div>
            </van-popup>
        </div>
    </div>

</template>
  
<script>
import { mapState } from 'vuex'
import router from './../../router'
export default {
    data(){
        return {
            // menu: router.options.routes.filter(item=>item.alwaysShow),
            defalutcActive: '1-1',
            style: {
                height: '100vh',
                width: '30vw'
            },
            menuSwitch2: false,
        }
    },
    watch: {
        $route: {
            handler(val){
                this.menuList?.forEach((item, index)=>{
                    if(val.path === item.path){
                        this.defalutcActive = `${index + 1}-1`
                    }
                })
            },
            immediate: true,
            deep: true
        },
        menuSwitch(val){
            this.menuSwitch2 = val
        }
    },
    computed: {
        ...mapState(['menuSwitch', 'menuList', 'deviceType']),
    },
    created(){
        // console.log('menu', this.menu)
    },
    methods: {
        handleOpen(){},
        handleClose(){},
        toPath(item){
            this.$router.push({
                path: item.path
            })
            this.$store.commit("add_historyRecord", item)
            if(this.deviceType !== 'pc') this.$store.commit('change_menuSwitch', false)
        },
        showMenu(){
            this.$store.commit('change_menuSwitch', true)
        },
        closeMenu(){
            this.$store.commit('change_menuSwitch', false)
        },
    }
}
</script>
  
<style lang="scss" scoped>
.menu{
    width: 250px;
    height: 100vh;
    background: #1F2D52;
    padding: 20px 0 0 0;
}
.menu-ani-close{
    animation: muneClose;
    animation-duration: 0.5s;
    width: 64px;
}
.menu-ani-open{
    animation: muneOpen;
    animation-duration: 0.5s;
    width: 250px;
}
@keyframes muneClose {
    0%{
        width: 250px;
    }
    100%{
        width: 64px;
    }
}
@keyframes muneOpen {
    0%{
        width: 64px;
    }
    100%{
        width: 250px;
    }
}
.logo{
    width: 132px;
    height: 30px;
    margin: 0 auto 20px;
    cursor: pointer;
}
::v-deep .el-menu .is-active{
    background: #1890FF !important;
}
::v-deep .el-menu{
    border: none;
}

.showMenu{
    position: fixed;
    top: 40vh;
    width: 5vw;
    height: 10vh;
    border: 1px solid #b6b3b3;
    border-left: none;
    background: #FFF;
    border-radius: 0 10px 10px 0;
}
.menuList{
    width: 30vw;
    height: 100vh;
    font-size: 14px;
    .item{
        padding: 10px 10px;
        border-bottom: 1px solid #e7e7e7;
    }
}

@media screen and (max-width: 750px) {

}

</style>
  